// Format user profile — Tool-compatible v3.1.0
// CRÍTICO: el LLM debe recibir instrucciones imperativas, no datos ambiguos.
const result = $input.first().json;
const isRegistered = result.registered === true;
const isSuccess    = result.success === true;

// Casos posibles:
// A) Usuario encontrado → dar datos + mensaje amable
// B) Usuario no encontrado (nuevo) → instrucción imperativa para el LLM
// C) Error real del DAL → mensaje de error técnico
let message;
let success;
let data;
let error_code = null;
let error_message = null;

if (!isSuccess) {
  // Caso C: error real del DAL
  success = false;
  error_code    = 'DAL_ERROR';
  error_message = 'Failed to fetch user profile';
  message = 'No se pudo consultar el perfil del usuario por un error interno. Informa al usuario que hay un problema técnico momentáneo e invítalo a intentar de nuevo en unos minutos.';
  data = null;
} else if (isRegistered) {
  // Caso A: usuario existe
  success = true;
  const name = result.data?.full_name || result.full_name || 'Paciente';
  message = `Usuario registrado encontrado. Nombre: ${name}. Email: ${result.data?.email || result.email || 'no disponible'}. Puedes usar estos datos para crear reservas sin pedirlos de nuevo.`;
  data = {
    registered:      true,
    user_id:         result.data?.user_id        || null,
    full_name:       result.data?.full_name       || result.full_name  || null,
    email:           result.data?.email           || result.email      || null,
    phone:           result.data?.phone           || null,
    active_bookings: result.data?.active_bookings || []
  };
} else {
  // Caso B: usuario nuevo — instrucción imperativa para el LLM
  success = true;  // No es un error, es un estado válido del sistema
  message = 'USUARIO NUEVO (no registrado). Instrucción: Salúdalo con calidez, dile que es su primera vez en la clínica y pídele su nombre completo y email para poder agendar su cita. NO menciones errores técnicos ni problemas de base de datos.';
  data = {
    registered:      false,
    user_id:         null,
    full_name:       null,
    email:           null,
    phone:           null,
    active_bookings: []
  };
}

return [{
  json: {
    success,
    message,
    error_code,
    error_message,
    data,
    _meta: { source: 'DB_Get_User_Profile', timestamp: new Date().toISOString(), version: '3.1.0' }
  }
}];

// 📤 STANDARD CONTRACT OUTPUT — Tool-compatible (v3.0.0)
// El AI Agent lee "message" como respuesta legible y "data" para detalles.
const result = $input.first()?.json || {};
const isSuccess = result.success !== false;

// Construir mensaje legible para el LLM
let message = result.message || result.data?.message || null;
if (!message) {
  message = isSuccess
    ? 'Operación completada con éxito.'
    : (result.error_message || result.error_code || 'Error desconocido.');
}

return [{
  json: {
    success: isSuccess,
    message,
    error_code:    isSuccess ? null : (result.error_code    || 'UNKNOWN_ERROR'),
    error_message: isSuccess ? null : (result.error_message || message),
    data:          result.data || null,
    _meta: {
      source:    'DB_GET_USER_PROFILE',
      timestamp: new Date().toISOString(),
      version:   '3.0.0'
    }
  }
}];
